import heapq

class MedianFinder:

    def __init__(self):
        self.max_heap = [] # Stores the smaller half of numbers (as negatives for max-heap behavior)
        self.min_heap = [] # Stores the larger half of numbers

    def addNum(self, num: int) -> None:
        if not self.max_heap or num <= -self.max_heap[0]:
            heapq.heappush(self.max_heap, -num)
        else:
            heapq.heappush(self.min_heap, num)

        # Rebalance heaps to maintain properties:
        # 1. len(max_heap) is equal to or one greater than len(min_heap)
        # 2. All elements in max_heap <= all elements in min_heap
        if len(self.max_heap) > len(self.min_heap) + 1:
            # max_heap is too large, move its largest element to min_heap
            val = heapq.heappop(self.max_heap)
            heapq.heappush(self.min_heap, -val)
        elif len(self.min_heap) > len(self.max_heap):
            # min_heap is too large, move its smallest element to max_heap
            val = heapq.heappop(self.min_heap)
            heapq.heappush(self.max_heap, -val)

    def findMedian(self) -> float:
        if len(self.max_heap) == len(self.min_heap):
            # Even number of elements, median is the average of the two middle elements
            return (-self.max_heap[0] + self.min_heap[0]) / 2.0
        else:
            # Odd number of elements, median is the top of the max_heap
            return float(-self.max_heap[0])

